INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-8b7f1efc-moex-00102', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政法法源，下列敘述何者正確？', '["各種法源效力平等，無位階之分", "行政法法源不僅只有成文法法源，一般法律原則亦為法源", "行政規則之訂定屬於行政行為，不得作為行政法之法源", "僅有通過立法行為，方能產生法源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00103', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '依司法院解釋意旨，關於層級化法律保留，下列敘述何者錯誤？', '["何種事項應以法律直接規範或得委由法規命令予以規定，與所涉權利義務有關", "若屬執行法律之細節性、技術性次要事項，則無須法律授權，得由行政機關依職權訂定行政規 則規範", "關於給付行政，法律規範密度較為寬鬆，倘涉及公共利益重大事項，仍有法律保留原則之適用", "涉及人民自由權利之限制者，如財產權，強調國會保留，即不得授權命令為補充性規範"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00104', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["社會秩序維護法第29條規定，違反本法行為之情節可憫恕者，得減輕或免除其處罰，屬於決 定裁量之範圍", "行政機關所選定之法律效果，逾越法律所授權之裁量範圍，則構成裁量逾越之瑕疵", "行政機關若消極地未斟酌具體個案情節，就作出決定，即構成裁量怠惰之瑕疵", "行政機關為裁量時，不受平等原則拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00105', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於地方自治團體權限之敘述，下列何者錯誤？', '["地方自治團體具有財政自主權，中央不得以法律規定地方分擔基於國家整體施政所需之經費", "地方自治團體有就自治事項制定規章並執行之權限", "地方自治團體對其是否設置特定機關或事業機構，享有自主組織權", "法律規定得設置之職位，地方自治團體既有自主決定設置與否之權限，仍應有組織自治條例之 依據始得進用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00106', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政組織之敘述，下列何者正確？', '["獨立機關是指依據法令獨立行使職權之機關", "政府與人民合資經營之事業，皆為公營事業", "依據公法所設立之組織體，皆為公法社團", "國家任務性質上不適宜由行政機關實施亦不適宜由民間實施者，得設立行政法人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00107', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政機關管轄權之敘述，下列何者正確？', '["行政機關不得透過行政規則或與其他機關簽訂契約來變更管轄權", "無管轄權之行政機關所作成之行政處分，均為無效", "人民不服財政部中區國稅局依法所為指定管轄之決定時，得向財政部提起訴願", "經濟部依法公告委託高雄市政府辦理高雄港區內工廠設立許可、登記、管理及輔導事項，為權 限委任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00108', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '依司法實務見解，關於公務員免職權限之敘述，下列何者正確？', '["公務員之免職為法院專屬權限", "行政機關以考績處分免除公務員之職務，牴觸憲法由司法院執掌懲戒權之規定", "公務員之免職權屬於行政機關人事權之固有核心", "對於公務員違法失職之行為，行政機關不得以考績處分處罰之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00109', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '依公務員服務法規定，關於公務員於法定工作時間以外之活動，下列敘述何者正確？', '["公務員應經服務機關同意，始得兼任經常營利性質之領證職業", "公務員應經服務機關同意，始得使用職稱發表與其服務機關業務職掌有關之言論", "公務員應經服務機關同意，始得依個人才藝表現，獲取適當報酬", "公務員應經服務機關同意，始得兼任無報酬且未影響本職之研究工作 13720、30120"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00110', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於公務員懲戒之敘述，下列何者正確？', '["退休（職、伍）之公務員於任職期間之違法失職行為，仍得予以懲戒", "公務員經受免除職務之懲戒者，其停止任用期間為10年以下", "懲戒法庭應本於書面而為判決，必要時得行言詞辯論", "同一行為已受刑罰之處罰者，不得予以懲戒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00111', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於法規命令之敘述，下列何者錯誤？', '["法規名稱為「細則」、「標準」者，通常屬於法規命令", "法規命令之訂定，為行政機關職權，人民不得提議為之", "主管機關擬訂法規命令時，如因情況急迫，顯然無法事先公告周知者，得不於政府公報或新聞 紙進行公告程序", "法規命令依法應經上級機關核定者，應於上級機關核定後，始可發布"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL)
